AMBER_PLATE = (5,5)
JADE_PLATE = (3,3)
GATE_A = (4,4)
GATE_B = (4,2)
RESET = (3,4)
RELIQ = (6,6)
RESET_CRATES = {'amber':(5,1),'jade':(2,1)}
DIRS = {'north':(-1,0),'south':(1,0),'west':(0,-1),'east':(0,1)}
DIR_ORDER = ['east','north','south','west']
